blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>podstawowy szyk wyrazów w zdaniu twierdzącym</strong>: strukturę S–V–O, miejsce przysłówków częstotliwości oraz pozycji czasu i miejsca.",
    "rules": [
        {
            "label": "Basic Structure",
            "color": "emerald",
            "text": "<strong>Subject + Verb + Object</strong> to podstawowy szkielet zdania:",
            "example": "She reads books."
        },
        {
            "label": "Adverbs of Frequency",
            "color": "blue",
            "text": "<strong>always, often, sometimes, never</strong> zwykle stoją przed głównym czasownikiem:",
            "example": "I always drink tea in the morning."
        },
        {
            "label": "Place + Time",
            "color": "amber",
            "text": "Informacje o miejscu i czasie zwykle pojawiają się pod koniec zdania:",
            "example": "We play football in the park every Sunday."
        }
    ]
}

{
    "title": "1. Struktura S–V–O (Subject–Verb–Object)",
    "intro": "Najprostsze angielskie zdanie twierdzące budujemy według schematu:",
    "items": [
        {
            "label": "S — Subject",
            "title": "Podmiot",
            "subtitle": "Kto albo co wykonuje czynność: I, you, she, Tom, the dog"
        },
        {
            "label": "V — Verb",
            "title": "Czasownik",
            "subtitle": "Czynność lub stan: read, eat, is, have"
        },
        {
            "label": "O — Object",
            "title": "Dopełnienie",
            "subtitle": "Na kogo lub na co skierowana jest czynność: book, coffee, him"
        }
    ]
}

{
    "title": "2. Przysłówki częstotliwości",
    "sections": [
        {
            "label": "Przed głównym czasownikiem",
            "color": "emerald",
            "description": "Przysłówki takie jak <strong>always, usually, often, sometimes, rarely, never</strong> stoją zwykle <strong>przed</strong> głównym czasownikiem.",
            "examples": [
                {
                    "en": "She always eats breakfast.",
                    "ua": "Ona zawsze je śniadanie."
                },
                {
                    "en": "I often go to the gym.",
                    "ua": "Często chodzę na siłownię."
                },
                {
                    "en": "They never drink coffee.",
                    "ua": "Oni nigdy nie piją kawy."
                }
            ]
        },
        {
            "label": "Po to be",
            "color": "sky",
            "description": "Jeśli w zdaniu występuje <strong>to be</strong>, przysłówek częstotliwości stoi zwykle <strong>po</strong> tej formie.",
            "examples": [
                {
                    "en": "He is always late.",
                    "ua": "On zawsze się spóźnia."
                },
                {
                    "en": "She is usually happy.",
                    "ua": "Ona jest zwykle szczęśliwa."
                },
                {
                    "en": "They are never bored.",
                    "ua": "Oni nigdy się nie nudzą."
                }
            ]
        },
        {
            "label": "Na początku dla akcentu",
            "color": "amber",
            "description": "Niektóre przysłówki, np. <strong>sometimes</strong>, <strong>usually</strong> albo <strong>often</strong>, mogą pojawić się na początku zdania, jeśli chcesz je podkreślić.",
            "examples": [
                {
                    "en": "Sometimes I read before bed.",
                    "ua": "Czasami czytam przed snem."
                },
                {
                    "en": "Usually we have dinner at 7.",
                    "ua": "Zwykle jemy kolację o siódmej."
                }
            ],
            "note": "Formy <strong>always</strong> i <strong>never</strong> rzadko stoją na początku zwykłego zdania twierdzącego."
        }
    ]
}

{
    "title": "3. Okoliczniki czasu",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Okoliczniki czasu, np. <strong>yesterday, every day, at 7 o'clock, last week</strong>, bardzo często stoją na końcu zdania.",
            "examples": [
                {
                    "en": "I wake up at 6 o'clock.",
                    "ua": "Budzę się o szóstej."
                },
                {
                    "en": "She studies English every day.",
                    "ua": "Ona codziennie uczy się angielskiego."
                },
                {
                    "en": "We went to the cinema last night.",
                    "ua": "Wczoraj wieczorem poszliśmy do kina."
                }
            ]
        },
        {
            "label": "Na początku zdania",
            "color": "sky",
            "description": "Jeśli chcesz zaakcentować informację o czasie, możesz przenieść ją na początek zdania.",
            "examples": [
                {
                    "en": "Yesterday, I met an old friend.",
                    "ua": "Wczoraj spotkałem starego przyjaciela."
                },
                {
                    "en": "Every morning, she jogs in the park.",
                    "ua": "Każdego ranka biega w parku."
                }
            ]
        }
    ]
}

{
    "title": "4. Okoliczniki miejsca",
    "sections": [
        {
            "label": "Po czasowniku albo dopełnieniu",
            "color": "emerald",
            "description": "Okoliczniki miejsca, takie jak <strong>at school, in the park, at home</strong>, stoją zwykle po czasowniku albo po dopełnieniu.",
            "examples": [
                {
                    "en": "He works at the office.",
                    "ua": "On pracuje w biurze."
                },
                {
                    "en": "She reads books in her room.",
                    "ua": "Ona czyta książki w swoim pokoju."
                }
            ]
        },
        {
            "label": "Miejsce przed czasem",
            "color": "sky",
            "description": "Jeśli w zdaniu masz i miejsce, i czas, zwykle najpierw pojawia się <strong>miejsce</strong>, a potem <strong>czas</strong>.",
            "examples": [
                {
                    "en": "We eat dinner at home on Sundays.",
                    "ua": "Jemy kolację w domu w niedziele."
                },
                {
                    "en": "The children play in the park every afternoon.",
                    "ua": "Dzieci bawią się w parku każdego popołudnia."
                }
            ]
        }
    ]
}

{
    "title": "5. Pełna struktura zdania",
    "intro": "W dłuższym zdaniu elementy często układają się tak:",
    "rows": [
        {
            "en": "Subject",
            "ua": "podmiot",
            "note": "She, Tom, They"
        },
        {
            "en": "Adverb of Frequency",
            "ua": "przysłówek częstotliwości",
            "note": "always, often, never"
        },
        {
            "en": "Verb",
            "ua": "czasownik",
            "note": "reads, eats, plays"
        },
        {
            "en": "Object",
            "ua": "dopełnienie",
            "note": "books, coffee, football"
        },
        {
            "en": "Place",
            "ua": "miejsce",
            "note": "at school, in the park"
        },
        {
            "en": "Time",
            "ua": "czas",
            "note": "every day, yesterday, at 7 o'clock"
        }
    ],
    "warning": "📌 W praktyce często otrzymasz schemat: <strong>S + (Adv) + V + O + Place + Time</strong>."
}

{
    "title": "6. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Niepoprawny szyk S–V–O.",
            "wrong": "Reads she books every day.",
            "right": "✅ <span class=\"font-mono\">She reads books every day.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Złe miejsce przysłówka częstotliwości.",
            "wrong": "She reads always books.",
            "right": "✅ <span class=\"font-mono\">She always reads books.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Wstawienie okolicznika czasu w nienaturalne miejsce.",
            "wrong": "I go every day to school.",
            "right": "✅ <span class=\"font-mono\">I go to school every day.</span>"
        }
    ]
}

{
    "title": "7. Krótkie podsumowanie",
    "items": [
        "Najprostszy szyk zdania twierdzącego to <strong>S + V + O</strong>.",
        "Przysłówki częstotliwości zwykle stoją <strong>przed głównym czasownikiem</strong> albo <strong>po to be</strong>.",
        "Okoliczniki czasu najczęściej pojawiają się <strong>na końcu zdania</strong>.",
        "Okoliczniki miejsca zwykle stoją po dopełnieniu i <strong>przed</strong> informacją o czasie.",
        "W dłuższych zdaniach przydaje się schemat: <strong>S + (Adv) + V + O + Place + Time</strong>."
    ]
}

{
    "title": "8. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny wariant",
    "select_intro": "Wskaż zdanie z naturalnym angielskim szykiem.",
    "selects": [
        {
            "label": "a) She always drinks coffee. / b) Always she drinks coffee.",
            "prompt": "Który wariant jest poprawny?"
        },
        {
            "label": "a) I go to work every day. / b) I every day go to work.",
            "prompt": "Który wariant jest poprawny?"
        },
        {
            "label": "a) He in the office works. / b) He works in the office.",
            "prompt": "Który wariant jest poprawny?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Ułóż zdanie we właściwym szyku",
    "input_intro": "Z podanych elementów zbuduj poprawne zdanie.",
    "inputs": [
        {
            "before": "(she / reads / books / often)",
            "after": "→"
        },
        {
            "before": "(every morning / I / breakfast / eat)",
            "after": "→"
        },
        {
            "before": "(at home / on Sundays / we / dinner / have)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw nienaturalny szyk zdania.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Plays he football every day.",
            "example_target": "He plays football every day."
        },
        {
            "original": "1. She reads always books in the evening.",
            "placeholder": "Popraw szyk zdania"
        },
        {
            "original": "2. We go every week to the supermarket.",
            "placeholder": "Popraw szyk zdania"
        }
    ]
}

{
    "title": "Strony w sekcji Word Order",
    "items": [
        {
            "label": "Basic Word Order — podstawowy szyk zdania",
            "current": true
        },
        {
            "label": "Word Order in Questions and Negatives — pytania i przeczenia",
            "current": false
        },
        {
            "label": "Word Order with Adverbs and Adverbials — przysłówki i okoliczniki",
            "current": false
        },
        {
            "label": "Word Order with Verbs and Objects — czasowniki i dopełnienia",
            "current": false
        },
        {
            "label": "Advanced Word Order / Emphasis — inwersja i akcent",
            "current": false
        }
    ]
}
